// В production Webhook данные лежат в $json.body
const update = $json.body ?? $json;

if (!update) {
  throw new Error("No update payload");
}

// Возможные типы апдейтов
const message = update.message ?? null;
const editedMessage = update.edited_message ?? null;
const callback = update.callback_query ?? null;
const preCheckout = update.pre_checkout_query ?? null;
const myChatMember = update.my_chat_member ?? null;
const chatMember = update.chat_member ?? null;

const successfulPayment = message?.successful_payment ?? null;

// Унифицированный пользователь
const from =
  callback?.from ??
  message?.from ??
  editedMessage?.from ??
  preCheckout?.from ??
  myChatMember?.from ??
  chatMember?.from ??
  null;

// Унифицированный chat
const chat =
  message?.chat ??
  editedMessage?.chat ??
  callback?.message?.chat ??
  myChatMember?.chat ??
  chatMember?.chat ??
  null;

const chatId = chat?.id ?? null;
const chatType = chat?.type ?? null;

const text =
  message?.text ??
  editedMessage?.text ??
  null;

const isStart =
  typeof text === "string" &&
  (text === "/start" || text.startsWith("/start "));

// Определяем тип события
let eventType = "unknown";

if (callback) {
  eventType = "callback";
} else if (preCheckout) {
  eventType = "pre_checkout";
} else if (successfulPayment) {
  eventType = "successful_payment";
} else if (text) {
  eventType = "text";
} else if (myChatMember) {
  eventType = "my_chat_member";
} else if (chatMember) {
  eventType = "chat_member";
}

// Платёжные поля
const invoicePayload =
  preCheckout?.invoice_payload ??
  successfulPayment?.invoice_payload ??
  null;

const totalAmount =
  preCheckout?.total_amount ??
  successfulPayment?.total_amount ??
  null;

const currency =
  preCheckout?.currency ??
  successfulPayment?.currency ??
  null;

const telegramPaymentChargeId =
  successfulPayment?.telegram_payment_charge_id ?? null;

const providerPaymentChargeId =
  successfulPayment?.provider_payment_charge_id ?? null;

// Поля membership update
const oldMemberStatus =
  myChatMember?.old_chat_member?.status ??
  chatMember?.old_chat_member?.status ??
  null;

const newMemberStatus =
  myChatMember?.new_chat_member?.status ??
  chatMember?.new_chat_member?.status ??
  null;

const botBlocked =
  eventType === "my_chat_member" &&
  newMemberStatus === "kicked";

const botUnblocked =
  eventType === "my_chat_member" &&
  (
    (oldMemberStatus === "kicked" && newMemberStatus === "member") ||
    (oldMemberStatus === "kicked" && newMemberStatus === "administrator")
  );

return [
  {
    json: {
      update_id: update.update_id ?? null,
      event_type: eventType,

      tg_user_id: from?.id ?? null,
      tg_username: from?.username ?? null,
      tg_first_name: from?.first_name ?? null,
      tg_last_name: from?.last_name ?? null,

      chat_id: chatId,
      chat_type: chatType,

      text,
      is_start: isStart,

      callback_data: callback?.data ?? null,
      callback_query_id: callback?.id ?? null,
      callback_message_id: callback?.message?.message_id ?? null,

      pre_checkout_query_id: preCheckout?.id ?? null,

      invoice_payload: invoicePayload,
      total_amount: totalAmount,
      currency,

      telegram_payment_charge_id: telegramPaymentChargeId,
      provider_payment_charge_id: providerPaymentChargeId,

      old_member_status: oldMemberStatus,
      new_member_status: newMemberStatus,
      bot_blocked: botBlocked,
      bot_unblocked: botUnblocked,

      successful_payment: successfulPayment ?? null,
      raw: update
    }
  }
];

const id = $json.id;
if (!id) throw new Error('No user id returned');
return [{ json: { user_id: Number(id) } }];

