// SAFE SESSION PARSER (handles: object | JSON string | double-encoded JSON string)
const raw =
  $json.session ??
  $json.redis?.session ??
  $json.redis?.data ??
  $json.data ??
  null;

let sess = {};

try {
  // 1) first parse (may return object OR string)
  let parsed = raw;

  if (typeof parsed === "string") {
    parsed = JSON.parse(parsed);
  }

  // 2) if still string => second parse (double-encoded)
  if (typeof parsed === "string") {
    parsed = JSON.parse(parsed);
  }

  // 3) only accept objects
  if (parsed && typeof parsed === "object" && !Array.isArray(parsed)) {
    sess = parsed;
  }
} catch (e) {
  sess = {};
}

// гарантируем структуру, чтобы дальше ничего не отваливалось
sess.active_request_id = sess.active_request_id ?? null;
sess.awaiting = sess.awaiting ?? "none";
sess.current_variant_idx = sess.current_variant_idx ?? "0";
sess.last_variant_idx = sess.last_variant_idx ?? "0";
sess.recipient_name = sess.recipient_name ?? null;
sess.last_inline_message_id = sess.last_inline_message_id ?? null;

return [{
  json: {
    ...$json,
    session: sess,
    active_request_id: sess.active_request_id ? String(sess.active_request_id) : null,
    awaiting: String(sess.awaiting || "none"),
    current_variant_idx: Number(sess.current_variant_idx || 0),
    last_variant_idx: Number(sess.last_variant_idx || 0),
  }
}];

const sess = {
  active_request_id: String($json.session.active_request_id),
  awaiting: "none",
  current_variant_idx: String($json.session.current_variant_idx || 0),
  last_variant_idx: String($json.session.last_variant_idx || 0),
};
return [{ ...$json, session_json: JSON.stringify(sess) }];

// FN_BUILD_TG_PAYLOAD (формирует tg_payload для HTTP node)

const chat_id = $json.chat_id ?? $node["FN_NORMALIZE"]?.json?.chat_id ?? null;
if (!chat_id) throw new Error("TG payload: chat_id is missing");

// Пример текста: если хочешь использовать именно текст входного сообщения — бери нормализованное $json.text
// (raw.message.text для callback часто null)
const sourceText = $json.text ?? "";

// ВАЖНО: делай текст обычной строкой, без риска поломать JSON на следующей ноде
const text = `Обращение зарегистрировано.\nПодготовка документа возможна немедленно.`;

// Если тебе реально надо подставлять sourceText — так безопаснее:
/// const text = `Обращение в отношении ${sourceText} зарегистрировано.\nПодготовка документа возможна немедленно.`;

return [
  {
    json: {
      ...$json,
      tg_payload: {
        chat_id,
        text,
        reply_markup: {
          inline_keyboard: [
            [{ text: "Подготовить документ", callback_data: "GEN_FIRST" }],
          ],
        },
      },
    },
  },
];

const awaiting = String($json.awaiting ?? $json.session?.awaiting ?? "none");
const text = $node["FN_NORMALIZE"].json.text ?? null;

const isWaitingInput = ["recipient_name", "delivery_username", "tz"].includes(awaiting);

return [{
  json: {
    ...$json,
    text_unexpected: !!text && !isWaitingInput
  }
}];

// FN_UPSERT_SESSION_FROM_UPDATE
// Вход ($json):
// - нормализованный update (event_type, tg_user_id, chat_id, raw, callback_message_id, ...)
// - session: строка JSON из Redis (как в твоём Merge-примере)

const update = $json;

// 1) parse redis session string (из Merge)
const rawSess =
  (typeof update.session === "string" ? update.session : null) ??
  (typeof update.redis?.session === "string" ? update.redis.session : null) ??
  (typeof update.redis?.data === "string" ? update.redis.data : null) ??
  null;

let session = {};
try {
  session = rawSess ? JSON.parse(String(rawSess)) : {};
} catch (e) {
  session = {};
}
if (!session || typeof session !== "object" || Array.isArray(session)) session = {};

// 2) canonical ids (апдейт имеет приоритет)
if (update.tg_user_id != null) session.tg_user_id = String(update.tg_user_id);
if (update.chat_id != null) session.chat_id = String(update.chat_id);
if (update.chat_type != null) session.chat_type = String(update.chat_type);

session.tg_username = update.tg_username ?? session.tg_username ?? null;
session.tg_first_name = update.tg_first_name ?? session.tg_first_name ?? null;
session.tg_last_name = update.tg_last_name ?? session.tg_last_name ?? null;

// 3) last_inline_message_id — ВСЕГДА обновляем на новый message_id (если нашли)
const msgId =
  update.callback_message_id ??
  update.raw?.callback_query?.message?.message_id ??
  update.raw?.message?.message_id ??
  update.raw?.edited_message?.message_id ??
  null;

if (msgId != null) {
  session.last_inline_message_id = String(msgId);
} else {
  // если вообще не нашли id — оставляем как было (или null, если не было)
  session.last_inline_message_id = session.last_inline_message_id ?? null;
}

// 4) FSM defaults (не затираем существующее, только гарантируем структуру)
session.active_request_id = session.active_request_id ?? null;
session.awaiting = session.awaiting ?? "none";
session.tariff_pending = session.tariff_pending ?? null;

session.current_variant_idx = String(session.current_variant_idx ?? "0");
session.last_variant_idx = String(session.last_variant_idx ?? "0");
session.recipient_name = session.recipient_name ?? null;

session.initiator_timezone = session.initiator_timezone ?? null;
session.tz_return_to = session.tz_return_to ?? null;

// 5) debug
session.last_update_id = update.update_id ?? session.last_update_id ?? null;
session.last_event_type = update.event_type ?? session.last_event_type ?? null;
session.last_callback_data = update.callback_data ?? session.last_callback_data ?? null;

return [{ json: { ...update, session } }];

// FN_BUILD_SESSION_FROM_NORMALIZED_UPDATE (FIXED)
// Вход: $json = нормализованный объект из твоего парсера

const input = $json;

// 0) восстановление существующей session (если ты подмешал её из Redis)
let session = {};

if (input.session && typeof input.session === "object") {
  session = { ...input.session };
} else if (typeof input.session === "string") {
  try {
    session = JSON.parse(input.session);
  } catch (e) {
    session = {};
  }
}

// 1) базовые идентификаторы
session.tg_user_id = input.tg_user_id != null ? String(input.tg_user_id) : (session.tg_user_id ?? null);
session.chat_id = input.chat_id != null ? String(input.chat_id) : (session.chat_id ?? null);
session.chat_type = input.chat_type ?? (session.chat_type ?? null);

session.tg_username = input.tg_username ?? (session.tg_username ?? null);
session.tg_first_name = input.tg_first_name ?? (session.tg_first_name ?? null);
session.tg_last_name = input.tg_last_name ?? (session.tg_last_name ?? null);

// 2) ✅ last_inline_message_id: берём message_id “кнопочного” сообщения
const inlineMsgId =
  input.callback_message_id ??                       // твой нормализатор (callback)
  input.raw?.callback_query?.message?.message_id ??  // запасной путь (callback)
  input.raw?.message?.message_id ??                  // текст/прочие события
  null;

if (inlineMsgId != null) {
  session.last_inline_message_id = String(inlineMsgId);
} else {
  session.last_inline_message_id = session.last_inline_message_id ?? null;
}

// 3) FSM поля (дефолты)
session.active_request_id = session.active_request_id ?? null;
session.awaiting = session.awaiting ?? "none";
session.tariff_pending = session.tariff_pending ?? null;

session.current_variant_idx = session.current_variant_idx ?? "0";
session.last_variant_idx = session.last_variant_idx ?? "0";
session.recipient_name = session.recipient_name ?? null;

session.initiator_timezone = session.initiator_timezone ?? null;
session.tz_return_to = session.tz_return_to ?? null;

// 4) служебные поля
session.last_update_id = input.update_id ?? (session.last_update_id ?? null);
session.last_event_type = input.event_type ?? (session.last_event_type ?? null);
session.last_callback_data = input.callback_data ?? (session.last_callback_data ?? null);

return [
  {
    json: {
      ...input,
      session
    }
  }
];

const p = $json.tg_payload;

return [{
  json: {
    ...$json,
    __debug_tg_payload_type: typeof p,
    __debug_tg_payload_isArray: Array.isArray(p),
    __debug_tg_payload_preview: (typeof p === 'string' ? p.slice(0, 200) : p),
  }
}];

// FN_NEXT_FSM_AND_BUILD_REDIS_SET
// Вход: $json = как в примере (update + уже распарсенная session-объектом)
// Задача: взять session, если сейчас ожидаем имя — принять текст как имя, перевести awaiting -> "none"
// и вернуть готовые поля для стандартного Redis SET (key/value/ttl) + session_json

const update = $json;

// 1) session (у тебя уже объект, но на всякий случай поддержим строку)
let session = update.session ?? {};
if (typeof session === "string") {
  try { session = JSON.parse(session); } catch (e) { session = {}; }
}
if (!session || typeof session !== "object") session = {};

// 2) всегда пишем новый message_id в last_inline_message_id (как ты хотел)
const newMsgId = update.raw?.message?.message_id ?? update.callback_message_id ?? null;
if (newMsgId != null) session.last_inline_message_id = String(newMsgId);

// 3) канонические поля из апдейта (не затираем важное, но обновляем идентификаторы/профиль)
if (update.tg_user_id != null) session.tg_user_id = String(update.tg_user_id);
if (update.chat_id != null) session.chat_id = String(update.chat_id);
if (update.chat_type != null) session.chat_type = String(update.chat_type);

session.tg_username = update.tg_username ?? session.tg_username ?? null;
session.tg_first_name = update.tg_first_name ?? session.tg_first_name ?? null;
session.tg_last_name = update.tg_last_name ?? session.tg_last_name ?? null;

// 4) FSM: если мы реально ждали имя — принимаем текст как recipient_name и выходим в awaiting=none
// (если сейчас awaiting уже "none", то НЕ трогаем recipient_name)
const awaiting = String(session.awaiting ?? "none");
const text = typeof update.text === "string" ? update.text.trim() : "";

if (awaiting === "recipient_name") {
  if (text) session.recipient_name = text;
  session.awaiting = "none";
}

// 5) дефолты, чтобы дальше не ломались
session.active_request_id = session.active_request_id ?? null;
session.current_variant_idx = String(session.current_variant_idx ?? "0");
session.last_variant_idx = String(session.last_variant_idx ?? "0");
session.tariff_pending = session.tariff_pending ?? null;
session.initiator_timezone = session.initiator_timezone ?? null;
session.tz_return_to = session.tz_return_to ?? null;

session.last_update_id = update.update_id ?? session.last_update_id ?? null;
session.last_event_type = update.event_type ?? session.last_event_type ?? null;
session.last_callback_data = update.callback_data ?? session.last_callback_data ?? null;

// 6) готовим выход под Redis SET
const redisKey = `razresheno:sess:${session.tg_user_id ?? update.tg_user_id}`;

// value лучше хранить строкой
const session_json = JSON.stringify(session);

return [
  {
    json: {
      ...update,
      session,
      redis: {
        key: redisKey,
        value: session_json,
        ttl: 86400,
      },
      session_json,
    },
  },
];

// 1) Достаём текст из разных возможных мест (n8n normalize у всех разный)
const rawText =
  $json.message?.text ??
  $json.update?.message?.text ??
  $json.body?.message?.text ??
  $json.text ??
  $json.message_text ??
  '';

let raw = String(rawText);

// 2) Чистим невидимые символы + переносы строк
raw = raw
  .replace(/[\u200B-\u200D\uFEFF]/g, '') // zero-width
  .replace(/\u00A0/g, ' ')               // NBSP
  .replace(/\r?\n|\r/g, '')
  .trim();

// 3) Иногда юзер присылает "email: xxx" — уберём префикс и пунктуацию по краям
raw = raw.replace(/^(e-?mail|email|почта)\s*:\s*/i, '');
raw = raw.replace(/^mailto:\s*/i, '');
raw = raw.replace(/^[<("'\s]+/, '').replace(/[>")'\s.,;:]+$/, '');

const email = raw.toLowerCase();

const session = $json.session;
if (!session) throw new Error('NO_SESSION');

// 4) Регэксп, который точно пропустит 9401689@gmail.com
const ok = /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

if (!ok) {
  return [{
    ok: false,
    error_message: "Похоже, email указан неверно. Пример: name@example.com",
    debug: {
      // покажем, что реально пришло
      rawText,
      normalized: email,
      charCodes: [...email].map(c => c.charCodeAt(0)),
      keys: Object.keys($json),
    },
    ...$json
  }];
}

session.customer_email = email;
session.awaiting_email = false;

return [{
  ok: true,
  session,
  email,
  ...$json
}];

const raw =
  $json.session ??
  $json.data ??
  $json.redis?.session ??
  $json.redis?.data ??
  null;

let sess = {};
try {
  sess = raw ? JSON.parse(raw) : {};
} catch (e) {
  sess = {};
}

// --- Гарантируем структуру ---
if (!sess || typeof sess !== 'object') {
  sess = {};
}

// Обязательные поля
sess.active_request_id = sess.active_request_id ?? null;
sess.awaiting = sess.awaiting ?? "none";
sess.recipient_name = sess.recipient_name ?? null;
sess.current_variant_idx = sess.current_variant_idx ?? "0";
sess.last_variant_idx = sess.last_variant_idx ?? "0";

// Новые поля для TZ логики
sess.initiator_timezone = sess.initiator_timezone ?? null;
sess.tariff_pending = sess.tariff_pending ?? null;

return [{
  json: {
    ...$json,
    session: sess,                  // <- ВАЖНО: возвращаем весь session
    active_request_id: sess.active_request_id // оставляем для совместимости
  }
}];

