let u = String($json.message?.text ?? '').trim();
u = u.replace(/\s+/g, '');
if (!u.startsWith('@')) u = '@' + u;

const ok = /^@[A-Za-z0-9_]{5,32}$/.test(u);
if (!ok) {
  return [{
    json: {
      ...$json,
      ok: false,
      error_message: "Неверный формат. Пример: @ivan_ivanov"
    }
  }];
}

// важный момент: awaiting сбрасываем только при успехе
