// Берём вход как есть
const input = $json;

// Гарантируем session
const session = { ...(input.session ?? {}) };

// Ставим FSM ожидание username
session.awaiting = 'email';

// Обычно полезно зафиксировать, что мы продолжаем тариф 199
// Если не нужно — удаляй эти 2 строки
session.tariff_pending = session.tariff_pending ?? '199';

// Служебное: обновим updated_at (если используешь)
session.updated_at = Date.now();

// Сформируем стандарт для Redis SET
const tgUserId = String(session.tg_user_id ?? input.tg_user_id ?? '');
if (!tgUserId) {
  throw new Error('NO_TG_USER_ID_FOR_REDIS_SESSION');
}

const redis_key = `razresheno:sess:${tgUserId}`;
const redis_value = JSON.stringify(session);
const redis_ttl = 86400;

return [{
  json: {
    ...input,
    session,
    redis_key,
    redis_value,
    redis_ttl,
  },
}];
